package main
import ("context";"encoding/json";"net/http";"github.com/go-chi/chi/v5";"github.com/jackc/pgx/v5/pgxpool")
func main(){db,_:=pgxpool.New(context.Background(),"postgres://postgres:postgres@postgres:5432/hypercompute?sslmode=disable");r:=chi.NewRouter();r.Get("/health",func(w http.ResponseWriter,r *http.Request){w.Write([]byte("ok"))});r.Get("/metrics",func(w http.ResponseWriter,r *http.Request){w.Write([]byte("billing_up 1"))});r.Post("/charge",func(w http.ResponseWriter,r *http.Request){var b map[string]any;json.NewDecoder(r.Body).Decode(&b);req:=b["request_id"].(string);var exists int;_ = db.QueryRow(r.Context(),"select count(1) from billing_records where request_id=$1",req).Scan(&exists);if exists>0{json.NewEncoder(w).Encode(map[string]any{"ok":true});return};tokens:=b["input_tokens"].(float64)+b["output_tokens"].(float64);amount:=tokens/1000.0*0.08;_,_=db.Exec(r.Context(),"insert into billing_records(request_id,user_id,node_id,model_name,input_tokens,output_tokens,amount,created_at) values($1,$2,$3,$4,$5,$6,$7,now())",req,int(b["user_id"].(float64)),b["node_id"],b["model"],int(b["input_tokens"].(float64)),int(b["output_tokens"].(float64)),amount);json.NewEncoder(w).Encode(map[string]any{"amount":amount})});http.ListenAndServe(":8083",r)}
